/* Nav Card - Supports dark mode & RTL */
.nav-card {
  background: var(--card-bg, #ffffff);
  border-radius: var(--card-radius, 16px);
  border: 1px solid var(--card-border, #e2e8f0);
  box-shadow: var(--card-shadow, 0 4px 6px -1px rgba(0,0,0,0.07));
  overflow: hidden;
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}
.nav-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 24px -4px rgba(0,0,0,0.12);
}

/* Nav Tabs */
.nav-card-tabs {
  display: flex;
  gap: 0;
  border-bottom: 1px solid var(--card-border, #e2e8f0);
  padding: 0 16px;
  background: var(--card-bg, #ffffff);
}
.nav-tab {
  padding: 10px 16px;
  font-size: 13px;
  font-weight: 500;
  color: #64748b;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
}
.nav-tab:hover { color: #3b82f6; }
.nav-tab.active {
  color: #3b82f6;
  border-bottom-color: #3b82f6;
  font-weight: 600;
}

/* Card Body */
.nav-card-body {
  padding: 20px;
}
.nav-card-image {
  position: relative;
  width: 100%;
  aspect-ratio: 16/9;
  overflow: hidden;
  border-radius: 10px;
  margin-bottom: 16px;
}
.nav-card-image img {
  width: 100%; height: 100%; object-fit: cover;
}
.nav-card-badge {
  position: absolute;
  top: 10px;
  left: 10px;
  background: #3b82f6;
  color: #fff;
  font-size: var(--badge-font-size, 11px);
  font-weight: 600;
  padding: 3px 10px;
  border-radius: 20px;
  letter-spacing: 0.5px;
  text-transform: uppercase;
}
[dir="rtl"] .nav-card-badge { left: auto; right: 10px; }
.nav-card-subtitle {
  font-size: var(--subtitle-font-size, 12px);
  font-weight: var(--subtitle-font-weight, 600);
  color: var(--subtitle-color, #64748b);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin: 0 0 4px;
}
.nav-card-title {
  font-size: var(--title-font-size, 18px);
  font-weight: var(--title-font-weight, 700);
  color: var(--title-color, #0f172a);
  margin: 0 0 8px;
  line-height: 1.4;
}
.nav-card-desc {
  font-size: var(--description-font-size, 14px);
  color: var(--description-color, #64748b);
  line-height: 1.6;
  margin: 0 0 14px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.nav-card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.nav-card-price {
  font-size: 20px;
  font-weight: 700;
  color: #0f172a;
}
.nav-card-btn {
  font-size: var(--button-font-size, 13px);
  font-weight: var(--button-font-weight, 600);
  color: var(--button-color, #3b82f6);
  text-decoration: none;
  transition: color 0.2s;
}
.nav-card-btn:hover { color: #2563eb; }

/* Dark Mode */
@media (prefers-color-scheme: dark) {
  .nav-card { background: #1e293b; border-color: #334155; }
  .nav-card-tabs { background: #1e293b; border-color: #334155; }
  .nav-card-title { color: #f1f5f9; }
  .nav-card-price { color: #f1f5f9; }
}
.dark .nav-card, [data-theme="dark"] .nav-card {
  background: #1e293b;
  border-color: #334155;
  color: #f1f5f9;
}
.dark .nav-card-tabs, [data-theme="dark"] .nav-card-tabs {
  background: #1e293b;
  border-color: #334155;
}
.dark .nav-card-title, [data-theme="dark"] .nav-card-title { color: #f1f5f9; }
.dark .nav-card-price, [data-theme="dark"] .nav-card-price { color: #e2e8f0; }

/* RTL Support */
[dir="rtl"] .nav-card-footer { flex-direction: row-reverse; }
[dir="rtl"] .nav-card-subtitle,
[dir="rtl"] .nav-card-title,
[dir="rtl"] .nav-card-desc {
  text-align: right;
}
